1	"use client";
2	
3	import dynamic from "next/dynamic";
4	import { useRouter } from "next/navigation";
5	import React, { useEffect, useRef, useState } from "react";
6	import { chatApi } from "@/features/chat/api/chatApi";
7	
8	// ssr:false — VoiceModeOverlay imports `livekit-client` (~1.5 MB raw bundled
9	// with @bufbuild/protobuf). Voice is opt-in, so the CLIENT bundle is split
10	// and livekit only fetches on demand. This does NOT remove livekit from the
11	// Cloudflare worker handler.mjs — OpenNext concatenates every chunk because
12	// CF Workers can't load chunks at runtime. The client-side win (no livekit
13	// in the initial JS download for chat users who don't use voice) is still
14	// worth keeping.
15	const VoiceApp = dynamic(
16	  () =>
17	    import("@/features/chat/components/composer/VoiceModeOverlay").then(
18	      (m) => m.VoiceApp,
19	    ),
20	  { ssr: false },
21	);
