1	/**
2	 * Mini chat surface shown above the Telegram / WhatsApp / Slack / Discord
3	 * picker in the `platforms` onboarding stage. Auto-rotates through the
4	 * platforms on a timer; a `hoveredPlatform` prop (driven by the connect
5	 * buttons) overrides the rotation while the user hovers a button.
6	 *
7	 * Messages are profession-keyed via `getPlatformScript` — the archetype
8	 * mapping lives in `constants/platformPreviewMessages.ts`.
9	 *
10	 * Auto-scroll: as the cascade grows the message list, the inner scrollable
11	 * column (each platform variant uses `overflow-y-auto`) is pinned to its
12	 * bottom so the newest bubble stays visible inside the fixed-height frame.
13	 */
14	
15	"use client";
16	
17	import { AnimatePresence } from "motion/react";
18	import * as m from "motion/react-m";
19	import Image from "next/image";
20	import { useEffect, useLayoutEffect, useMemo, useRef, useState } from "react";
21	import { ChatDemo } from "@/features/landing/components/iphone/ChatDemo";
22	import {
23	  cascadeDurationMs,
24	  useStaggeredMessages,
25	} from "@/features/landing/components/iphone/useStaggeredMessages";
26	import {
27	  getPlatformScript,
28	  PLATFORM_ICONS,
29	  PLATFORM_LABELS,
30	  PLATFORM_PREVIEW_ORDER,
31	  type PlatformPreviewPlatform,
32	} from "../constants/platformPreviewMessages";
33	
34	const DWELL_MS = 1800;
35	
36	interface OnboardingPlatformPreviewProps {
37	  profession: string | undefined;
38	  hoveredPlatform: PlatformPreviewPlatform | null;
39	  userName: string | undefined;
40	  userAvatar: string | undefined;
41	}
42	
43	export function OnboardingPlatformPreview({
44	  profession,
45	  hoveredPlatform,
46	  userName,
47	  userAvatar,
48	}: OnboardingPlatformPreviewProps) {
49	  const [rotatingPlatform, setRotatingPlatform] =
50	    useState<PlatformPreviewPlatform>(PLATFORM_PREVIEW_ORDER[0]);
51	
52	  const activePlatform = hoveredPlatform ?? rotatingPlatform;
53	
54	  const script = useMemo(
55	    () =>
56	      getPlatformScript(profession, activePlatform, {
57	        name: userName,
58	        avatar: userAvatar,
59	      }),
60	    [profession, activePlatform, userName, userAvatar],
61	  );
62	
63	  const visibleMessages = useStaggeredMessages(script.messages, true);
64	
65	  const scrollHostRef = useRef<HTMLDivElement>(null);
66	
67	  useLayoutEffect(() => {
68	    const scroller =
69	      scrollHostRef.current?.querySelector<HTMLElement>(".overflow-y-auto");
70	    if (!scroller) return;
71	    scroller.scrollTop = scroller.scrollHeight;
72	  }, [visibleMessages, activePlatform]);
73	
74	  useEffect(() => {
75	    if (hoveredPlatform) return;
76	    const cascadeMs = cascadeDurationMs(script.messages.length);
77	    const id = window.setTimeout(() => {
78	      setRotatingPlatform((current) => {
79	        const idx = PLATFORM_PREVIEW_ORDER.indexOf(current);
80	        return PLATFORM_PREVIEW_ORDER[
81	          (idx + 1) % PLATFORM_PREVIEW_ORDER.length
82	        ];
83	      });
84	    }, cascadeMs + DWELL_MS);
85	    return () => window.clearTimeout(id);
86	  }, [hoveredPlatform, script]);
87	
